.projects {
  background-color: var(--background-light);
  color: var(--text-dark);
  text-align: center;
}

.sectionTitle {
  font-size: clamp(2em, 4vw, 3.5em);
  margin-bottom: 40px;
  color: var(--primary-color);
  position: relative;
}

.sectionTitle::after {
content: '';
  position: absolute;
  bottom: -10px;
  left: 50%;
  transform: translateX(-50%);
  width: 80px;
height: 4px;
  background-color: var(--accent-color);
  border-radius: 2px;
}

.projectsGrid {
  display: grid;
  grid-template-columns: repeat(auto-fit, minmax(300px, 1fr));
  gap: 40px;
  margin-top: 50px;
}

.projectCard {
  background-color: #fff;
  border-radius: 10px;
  box-shadow: 0 8px 20px rgba(0, 0, 0,0.1);
  overflow: hidden;
  display: flex;
  flex-direction: column;
  transition: transform 0.3s ease, box-shadow 0.3s ease;
}

.projectCard:hover {
  transform: translateY(-10px);
  box-shadow: 0 12px 25px rgba(0, 0, 0, 0.15);
}

.projectImage {
  width: 100%;
  height: 200px; /* Fixed height for consistent cards */
  object-fit: cover;
}

.projectInfo {
  padding: 25px;
  text-align: left;
  flex-grow: 1;
  display: flex;
  flex-direction: column;
}

.projectTitle{
  font-size: 1.8em;
  color: var(--primary-color);
  margin-bottom: 10px;
}

.projectDescription {
  font-size: 1em;
  color: var(--text-dark);
  line-height: 1.6;
  margin-bottom: 15px;
  flex-grow: 1;
}

.projectTech {
  margin-top: 15px;
  margin-bottom: 20px;
  display: flex;
  flex-wrap: wrap;
  gap: 8px;
}

.techTag {
  background-color: var(--secondary-color);
  color: var(--text-light);
  padding: 6px 12px;
  border-radius:5px;
  font-size: 0.85em;
  font-weight: 500;
}

.projectLinks {
  display: flex;
  gap: 15px;
  margin-top: auto; /* Push links to the bottom */
}

.linkButton {
  display: inline-block;
  padding: 12px 20px;
background-color: var(--primary-color);
  color: var(--text-light);
  border-radius: 5px;
  font-weight: 600;
  transition: background-color 0.3s ease;
}

.linkButton:hover {
  background-color: #0056b3;
  text-decoration: none;
}

.repoButton {
background-color: var(--secondary-color);
}

.repoButton:hover {
  background-color: #5a6268;
}

/* Media Queries */
@media (max-width: 768px) {
  .projectsGrid {
    grid-template-columns: 1fr;
  }
}
