@import "tailwindcss";

:root {
  --background: 240 10% 4%;
  --foreground: 20 10% 98%;
  --primary: 25 80% 60%;
  --primary-foreground: 210 40% 98%;
  --card: 240 10% 6%;
  --card-foreground: 20 10% 98%;
  --muted: 240 5% 15%;
  --muted-foreground: 240 5% 65%;
  --border: 240 5% 15%;
}

body {
  font-family: 'Inter', sans-serif;
  background: hsl(var(--background));
  color: hsl(var(--foreground));
  margin: 0;
}

