src/components/Features.tsx.content:
import { Brain, Zap, Shield, Globe, Code, Layers } from 'lucide-react';
import { motion } from 'framer-motion';

const features = [
  {
    icon: Brain,
    title: "AI-Powered",
    description: "Intelligent code generation and suggestions powered by advanced LLMs.",
    color: "text-purple-400",
  },
  {
    icon: Zap,
    title: "Lightning Fast",
    description: "Optimized build pipeline for instant hot reloading.",
    color: "text-yellow-400",
  },
  {
    icon: Shield,
    title: "Secure by Default",
    description: "Enterprise-grade security built into every layer.",
    color: "text-green-400",
  },
  {
    icon: Globe,
    title: "Edge Ready",
    description: "Deploy to the edge in one click with CDN support.",
    color: "text-blue-400",
  },
];

export default function Features() {
  return (
    <section className="py-24 bg-card/30">
      <div className="container mx-auto px-4">
        <h2 className="text-4xl font-bold text-center mb-16">Features</h2>
        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6">
          {features.map((feature, i) => (
            <motion.div
              key={i}
              initial={{ opacity: 0, y: 20 }}
              whileInView={{ opacity: 1, y: 0 }}
              transition={{ delay: i * 0.1 }}
              className="p-6 rounded-2xl bg-card border border-border hover:border-primary/30 transition-colors"
            >
              <feature.icon className={`w-8 h-8 ${feature.color} mb-4`} />
              <h3 className="text-lg font-semibold mb-2">{feature.title}</h3>
              <p className="text-sm text-muted-foreground">{feature.description}</p>
            </motion.div>
          ))}
        </div>
      </div>
    </section>
  );
}

