import React from 'react';
import styles from './Skills.module.css';

const skillsList = [
  { name: 'HTML5', icon: 'fab fa-html5', category: 'Frontend' },
  { name: 'CSS3', icon: 'fab fa-css3-alt', category: 'Frontend' },
  { name: 'JavaScript', icon: 'fab fa-js-square', category: 'Frontend' },
  { name: 'React', icon: 'fab fa-react', category: 'Frontend' },
  { name: 'Vue.js', icon: 'fab fa-vuejs', category: 'Frontend' },
  { name: 'Node.js', icon: 'fab fa-node-js', category: 'Backend' },
  { name: 'Express.js', icon:'fas fa-server', category: 'Backend' },
  { name: 'Python', icon: 'fab fa-python', category: 'Backend' },
  { name: 'MongoDB', icon: 'fasfa-database', category: 'Database' },
  { name: 'SQL', icon: 'fas fa-database', category: 'Database' },
  { name: 'Git', icon: 'fab fa-git-alt', category: 'Tools' },
  { name: 'Figma', icon: 'fab fa-figma', category: 'Tools' },
  { name: 'Responsive Design', icon: 'fas fa-mobile-alt', category: 'Concepts' },
];

const Skills = () => {
  // For a more advanced portfolio, you might group skills by category
  const categories = [...new Set(skillsList.map(skill => skill.category))];

  return (
    <section id="skills" className={styles.skills}>
      <div className={`${styles.skillsContent} container`}>
<h2 className={styles.sectionTitle}>My Skills</h2>
        <div className={styles.skillsGrid}>
          {categories.map(category => (
            <div key={category} className={styles.skillCategory}>
              <h3 className={styles.categoryTitle}>{category}</h3>
              <div className={styles.categorySkills}>
                {skillsList.filter(skill => skill.category === category).map(skill => (
                  <div key={skill.name} className={styles.skillItem}>
                    {skill.icon && <i className={`${skill.icon} ${styles.skillIcon}`}></i>}
                    <span className={styles.skillName}>{skill.name}</span>
                  </div>
                ))}
              </div>
            </div>
          ))}
        </div>
      </div>
    </section>
  );
};

export defaultSkills;

