/* src/components/Skills.module.css */
.skills {
  background-color: var(--background-dark);
  color: var(--text-light);
  text-align: center;
}

.sectionTitle {
  font-size: clamp(2em, 4vw, 3.5em);
  margin-bottom: 40px;
  color: var(--accent-color);
  position: relative;
}

.sectionTitle::after {
  content: '';
  position: absolute;
  bottom: -10px;
  left: 50%;
  transform: translateX(-50%);
  width: 80px;
  height: 4px;
  background-color: var(--primary-color);
  border-radius: 2px;
}

.skillsGrid {
  display: grid;
grid-template-columns: repeat(auto-fit, minmax(250px, 1fr));
  gap: 30px;
  margin-top: 50px;
}

.skillCategory {
  background-color: #333;
  border-radius: 10px;
  padding: 30px;
  box-shadow: 0 5px 15px rgba(0, 0, 0, 0.3);
  transition: transform 0.3s ease, box-shadow 0.3s ease;
}

.skillCategory:hover {
transform: translateY(-5px);
  box-shadow: 0 8px 20px rgba(0, 0, 0, 0.4);
}

.categoryTitle {
  font-size: 1.8em;
  color: var(--accent-color);
  margin-bottom: 25px;
}

.categorySkills {
  display: flex;
  flex-wrap: wrap;
  justify-content: center;
  gap: 15px;
}

.skillItem {
  display: flex;
  flex-direction: column;
  align-items: center;
  justify-content: center;
  padding: 15px;
  background-color: #444;
  border-radius: 8px;
  min-width:100px;
  color: var(--text-light);
  box-shadow: 0 2px 5px rgba(0, 0, 0, 0.2);
  transition:background-color 0.2s ease;
}

.skillItem:hover {
  background-color: var(--primary-color);
}

.skillIcon {
  font-size:2.5em;
  margin-bottom: 10px;
  color: var(--accent-color);
}

.skillItem:hover .skillIcon {
  color: var(--text-light);
}

.skillName {
  font-size: 1em;
  font-weight: 500;
}

