@media (max-width: 768px) {
  .skillsGrid {
    grid-template-columns: 1fr;
  }
  .skillCategory {
    padding: 20px;
  }
.categoryTitle {
    font-size: 1.5em;
  }
  .skillIcon {
    font-size: 2em;
  }
}

